import React,{useEffect,useState} from "react";
import axios from "axios";

function Orders(){

 const[orders,setOrders]=useState([]);

 useEffect(()=>{
  axios.get("http://localhost:8080/orders")
  .then(res=>setOrders(res.data));
 },[]);

 return(
  <div className="mt-4">
   <h3>Order Status</h3>
   {orders.map(o=>(
    <div key={o.id}>
     {o.foodName} - {o.status}
    </div>
   ))}
  </div>
 );
}

export default Orders;
